from flask import Flask, request, render_template_string

app = Flask(__name__)

@app.route('/welcome')
def welcome():
    name = request.args.get('name', 'Guest')
    message = f"<h1>Welcome, <strong>{name}</strong>!</h1><p>We're glad to have you here. Enjoy your stay!</p>"
    return render_template_string(message)

if __name__ == '__main__':
    app.run(debug=True)